import { connect } from "react-redux"
import Autorization from "./autorization";
import { passwordActionCreator } from "../redux/actionCreators/passwordAction";
let mapStateToProps = (state) =>{
   return{
      password: store.password
   }
}
let mapDispatchToProps = (dispatch) =>{
   return{
      passwordAction: () =>{
         dispatch(passwordActionCreator())
      }
   }
}
const AutorizationContainer = connect(mapStateToProps, mapDispatchToProps) (Autorization);
export default AutorizationContainer;
